import React, { useState, useEffect, useMemo } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI, Type } from "@google/genai";

// --- Mock Data ---
interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
  description: string;
  specs: string[];
  color: string;
  imageUrl: string;
}

const PRODUCTS: Product[] = [
  { id: '1', name: 'Nebula Pro Laptop', category: 'Laptops', price: 1299, description: 'High-end gaming and creative laptop.', specs: ['RTX 4080', '32GB RAM', '2TB SSD'], color: 'Space Gray', imageUrl: 'https://images.unsplash.com/photo-1496181133206-80ce9b88a853?w=400&h=300&fit=crop' },
  { id: '2', name: 'SilentKey Mechanical', category: 'Keyboards', price: 150, description: 'Premium quiet switches for office and gaming.', specs: ['Hot-swappable', 'RGB', 'Wireless'], color: 'Black', imageUrl: 'https://images.unsplash.com/photo-1511467687858-23d96c32e4ae?w=400&h=300&fit=crop' },
  { id: '3', name: 'SonicBlast Buds', category: 'Audio', price: 199, description: 'True wireless noise cancelling earbuds.', specs: ['ANC', '40h Battery', 'IPX7'], color: 'White', imageUrl: 'https://images.unsplash.com/photo-1590658268037-6bf12165a8df?w=400&h=300&fit=crop' },
  { id: '4', name: 'UltraWide View 34"', category: 'Monitors', price: 450, description: 'Curved productivity powerhouse.', specs: ['144Hz', 'IPS', 'USB-C Charging'], color: 'Silver', imageUrl: 'https://images.unsplash.com/photo-1527443224154-c4a3942d3acf?w=400&h=300&fit=crop' },
  { id: '5', name: 'SmartHome Hub Pro', category: 'Smart Home', price: 89, description: 'Central controller for all your devices.', specs: ['Zigbee', 'Matter Support', 'Voice Assistant'], color: 'White', imageUrl: 'https://images.unsplash.com/photo-1558002038-103792e07924?w=400&h=300&fit=crop' },
  { id: '6', name: 'PixelDraw Tablet', category: 'Tablets', price: 699, description: 'Designed for digital artists.', specs: ['Pressure Sensitive Pen', '2K Display', '120Hz'], color: 'Blue', imageUrl: 'https://images.unsplash.com/photo-1544244015-0df4b3ffc6b0?w=400&h=300&fit=crop' },
  { id: '7', name: 'LiteBook Air', category: 'Laptops', price: 899, description: 'Ultra-thin, ultra-portable workstation.', specs: ['12h Battery', 'Fanless', 'Retina Display'], color: 'Rose Gold', imageUrl: 'https://images.unsplash.com/photo-1517336714731-489689fd1ca8?w=400&h=300&fit=crop' },
  { id: '8', name: 'MacroClick Mouse', category: 'Accessories', price: 45, description: 'Affordable ergonomic office mouse.', specs: ['3200 DPI', 'Wireless', 'Soft Touch'], color: 'Black', imageUrl: 'https://images.unsplash.com/photo-1527864550417-7fd91fc51a46?w=400&h=300&fit=crop' },
];

const App = () => {
  const [query, setQuery] = useState('');
  const [filteredIds, setFilteredIds] = useState<string[]>(PRODUCTS.map(p => p.id));
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!query.trim()) {
      setFilteredIds(PRODUCTS.map(p => p.id));
      return;
    }

    setIsAiLoading(true);
    setError(null);

    try {
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Given the following product catalog as a JSON list, filter it based on the user's natural language request: "${query}". 
        Return ONLY a JSON array containing the "id" strings of the matching products. 
        If no products match, return an empty array [].

        Catalog: ${JSON.stringify(PRODUCTS.map(p => ({ id: p.id, name: p.name, category: p.category, price: p.price, color: p.color, specs: p.specs, description: p.description })))}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        }
      });

      const resultIds = JSON.parse(response.text || '[]');
      setFilteredIds(resultIds);
    } catch (err) {
      console.error("AI Filtering Error:", err);
      setError("Hubo un problema al procesar tu búsqueda con IA.");
      // Fallback to simple keyword search if AI fails
      const fallback = PRODUCTS.filter(p => 
        p.name.toLowerCase().includes(query.toLowerCase()) || 
        p.description.toLowerCase().includes(query.toLowerCase())
      ).map(p => p.id);
      setFilteredIds(fallback);
    } finally {
      setIsAiLoading(false);
    }
  };

  const displayedProducts = useMemo(() => 
    PRODUCTS.filter(p => filteredIds.includes(p.id)), 
  [filteredIds]);

  return (
    <div className="min-h-screen p-4 md:p-8 max-w-7xl mx-auto">
      {/* Header */}
      <header className="mb-12 text-center">
        <h1 className="text-4xl md:text-6xl font-bold mb-4 heading-font bg-gradient-to-r from-blue-400 to-emerald-400 bg-clip-text text-transparent">
          TechAI Discovery
        </h1>
        <p className="text-slate-400 text-lg">Explora nuestro catálogo usando lenguaje natural.</p>
      </header>

      {/* AI Search Bar */}
      <section className="max-w-2xl mx-auto mb-16">
        <form onSubmit={handleSearch} className="relative group">
          <div className="absolute -inset-1 bg-gradient-to-r from-blue-600 to-emerald-600 rounded-2xl blur opacity-25 group-focus-within:opacity-75 transition duration-500"></div>
          <div className="relative flex items-center">
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Ej: 'Laptop potente para diseño' o 'accesorios baratos blancos'..."
              className="w-full px-6 py-4 bg-slate-900 border border-slate-700 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all text-lg"
            />
            <button
              type="submit"
              disabled={isAiLoading}
              className="absolute right-3 px-6 py-2 bg-gradient-to-r from-blue-600 to-emerald-600 hover:from-blue-500 hover:to-emerald-500 text-white font-semibold rounded-lg transition-all disabled:opacity-50"
            >
              {isAiLoading ? 'Filtrando...' : 'Filtrar con IA'}
            </button>
          </div>
        </form>
        {error && <p className="mt-2 text-red-400 text-sm text-center">{error}</p>}
      </section>

      {/* Grid */}
      <main>
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-semibold heading-font">
            {isAiLoading ? 'Analizando catálogo...' : `${displayedProducts.length} Resultados`}
          </h2>
          <button 
            onClick={() => { setQuery(''); setFilteredIds(PRODUCTS.map(p => p.id)); }}
            className="text-slate-400 hover:text-white transition-colors text-sm"
          >
            Limpiar Filtros
          </button>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {isAiLoading ? (
            // Shimmer Loaders
            Array.from({ length: 4 }).map((_, i) => (
              <div key={i} className="glass rounded-2xl overflow-hidden h-[400px]">
                <div className="loading-shimmer w-full h-48"></div>
                <div className="p-6 space-y-4">
                  <div className="loading-shimmer h-6 w-3/4 rounded"></div>
                  <div className="loading-shimmer h-4 w-full rounded"></div>
                  <div className="loading-shimmer h-4 w-1/2 rounded"></div>
                </div>
              </div>
            ))
          ) : displayedProducts.length > 0 ? (
            displayedProducts.map((product) => (
              <div key={product.id} className="glass rounded-2xl overflow-hidden group hover:border-blue-500/50 transition-all duration-300 transform hover:-translate-y-1">
                <div className="relative h-48 overflow-hidden">
                  <img 
                    src={product.imageUrl} 
                    alt={product.name}
                    className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
                  />
                  <div className="absolute top-3 right-3 bg-black/60 backdrop-blur-md px-3 py-1 rounded-full text-xs font-bold text-emerald-400">
                    ${product.price}
                  </div>
                </div>
                <div className="p-6">
                  <span className="text-[10px] uppercase tracking-widest text-blue-400 font-bold mb-2 block">
                    {product.category} • {product.color}
                  </span>
                  <h3 className="text-xl font-bold mb-2 heading-font">{product.name}</h3>
                  <p className="text-slate-400 text-sm line-clamp-2 mb-4">
                    {product.description}
                  </p>
                  <div className="flex flex-wrap gap-2">
                    {product.specs.map((spec, idx) => (
                      <span key={idx} className="bg-slate-800 text-slate-300 px-2 py-1 rounded text-[10px] font-medium border border-slate-700">
                        {spec}
                      </span>
                    ))}
                  </div>
                </div>
              </div>
            ))
          ) : (
            <div className="col-span-full py-20 text-center">
              <p className="text-slate-500 text-xl">No se encontraron productos que coincidan con tu búsqueda.</p>
              <button 
                onClick={() => { setQuery(''); setFilteredIds(PRODUCTS.map(p => p.id)); }}
                className="mt-4 text-blue-400 hover:underline"
              >
                Ver todo el catálogo
              </button>
            </div>
          )}
        </div>
      </main>

      {/* Footer Info */}
      <footer className="mt-20 py-8 border-t border-slate-800 text-center text-slate-500 text-sm">
        &copy; 2024 TechAI Discovery Platform. Powered by Gemini 3 Flash.
      </footer>
    </div>
  );
};

const container = document.getElementById('root');
const root = createRoot(container!);
root.render(<App />);

{
  "description": "A futuristic tech product discovery app featuring natural language filtering powered by Gemini AI."
}
